class DistributedSessionService
  def self.load_from_cookie(cookies)
    session_cookie = cookies[:_marshal_session]
    return {} unless session_cookie
    
    decoded = Base64.decode64(session_cookie)
    Marshal.load(decoded)
  rescue => e
    Rails.logger.error("Failed to load session from cookie: #{e.message}")
    {}
  end

  def self.save_to_cookie(cookies, session_data)
    serialized = Marshal.dump(session_data)
    encoded = Base64.encode64(serialized).gsub("\n", '')
    
    cookies[:_marshal_session] = {
      value: encoded,
      expires: 24.hours.from_now,
      httponly: true,
      secure: Rails.env.production?
    }
  rescue => e
    Rails.logger.error("Failed to save session to cookie: #{e.message}")
  end

  def self.sync_session(cookies, updates = {})
    current_session = load_from_cookie(cookies)
    merged_session = current_session.merge(updates)
    save_to_cookie(cookies, merged_session)
    merged_session
  end
end